Here's a secure and well-structured implementation of a login system using Node.js, Express, and bcrypt. This example includes both registration and authentication with session-based security.

```javascript
// server.js
const express = require('express');
const bcrypt = require('bcrypt');
const session = require('express-session');
const app = express();
const PORT = 3000;

// In-memory database simulation
const users = [];

// Middleware
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(session({
  secret: process.env.SESSION_SECRET || 'your-secure-secret-key',
  resave: false,
  saveUninitialized: true,
  cookie: {
    secure: process.env.NODE_ENV === 'production', // Use HTTPS in production
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 1000 * 60 * 60 * 24 // 1 day
  }
}));

// Registration endpoint
app.post('/register', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Input validation
    if (!username || !password) {
      return res.status(400).json({ error: 'Username and password are required' });
    }

    if (username.length < 3) {
      return res.status(400).json({ error: 'Username must be at least 3 characters' });
    }

    if (password.length < 8) {
      return res.status(400).json({ error: 'Password must be at least 8 characters' });
    }

    // Check for existing user
    const existingUser = users.find(user => user.username === username);
    if (existingUser) {
      return res.status(400).json({ error: 'Username already exists' });
    }

    // Hash password
    const saltRounds = 10;
    const hashedPassword = await bcrypt.hash(password, saltRounds);

    // Store user (in production, store in database)
    users.push({
      id: users.length + 1,
      username: username.toLowerCase(),
      password: hashedPassword
    });

    res.status(201).json({ message: 'User created successfully' });
  } catch (error) {
    console.error('Registration error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Login endpoint
app.post('/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Find user
    const user = users.find(user => user.username === username.toLowerCase());
    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Compare passwords
    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Create session
    req.session.user = {
      id: user.id,
      username: user.username
    };

    res.json({ message: 'Login successful', user: req.session.user });
  } catch (error) {
    console.error('Login error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Protected route
app.get('/dashboard', (req, res) => {
  if (!req.session.user) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  res.json({
    message: 'Welcome to the dashboard',
    user: req.session.user
  });
});

// Logout endpoint
app.post('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).json({ error: 'Could not log out' });
    }
    res.clearCookie('connect.sid');
    res.json({ message: 'Logged out successfully' });
  });
});

// Start server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

**Key Security Features:**

1. **Password Security:**
   - Uses bcrypt for secure password hashing with salt
   - 10-round bcrypt hash (adjustable for security/performance balance)
   - Never stores plain text passwords

2. **Session Security:**
   - Secure session configuration with HTTP-only cookies
   - Session expiration (1 day in this example)
   - Proper session destruction on logout

3. **Input Validation:**
   - Minimum password length requirements
   - Username uniqueness check
   - Case-insensitive username handling

4. **Security Best Practices:**
   - Generic error messages to prevent information leakage
   - Secure cookie attributes (HttpOnly, SameSite)
   - Session regeneration on login

**To Use This Example:**

1. Install dependencies:
```bash
npm init -y
npm install express bcrypt express-session
```

2. Create a `server.js` file with the code above

3. Start the server:
```bash
node server.js
```

**Example Requests:**

1. Register a user:
```http
