Here's a step-by-step guide to building a basic admin dashboard for a user management system using **React (frontend)** and **Node.js/Express (backend)** with **MongoDB**. This example includes user CRUD operations and a simple UI.

---

### **1. Backend Setup (Node.js/Express/MongoDB)**

**Folder Structure:**
```
backend/
├── models/
│   └── User.js
├── routes/
│   └── userRoutes.js
├── server.js
└── .env
```

#### **1.1 Install Dependencies**
```bash
npm init -y
npm install express mongoose cors dotenv
```

#### **1.2 `server.js`**
```javascript
const express = require("express");
const mongoose = require("mongoose");
const cors = require("cors");
const userRoutes = require("./routes/userRoutes");
require("dotenv").config();

const app = express();
app.use(cors());
app.use(express.json());

// Connect to MongoDB
mongoose.connect(process.env.MONGO_URI, {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

app.use("/api/users", userRoutes);

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

#### **1.3 `.env`**
```
MONGO_URI=mongodb://localhost:27017/usermanagement
PORT=5000
```

#### **1.4 `models/User.js`**
```javascript
const mongoose = require("mongoose");

const UserSchema = new mongoose.Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  role: { type: String, enum: ["admin", "user"], default: "user" },
});

module.exports = mongoose.model("User", UserSchema);
```

#### **1.5 `routes/userRoutes.js`**
```javascript
const express = require("express");
const User = require("../models/User");
const router = express.Router();

// Get all users
router.get("/", async (req, res) => {
  const users = await User.find();
  res.json(users);
});

// Create user
router.post("/", async (req, res) => {
  const user = new User(req.body);
  await user.save();
  res.status(201).json(user);
});

// Update user
router.put("/:id", async (req, res) => {
  const user = await User.findByIdAndUpdate(req.params.id, req.body, { new: true });
  res.json(user);
});

// Delete user
router.delete("/:id", async (req, res) => {
  await User.findByIdAndDelete(req.params.id);
  res.json({ message: "User deleted" });
});

module.exports = router;
```

---

### **2. Frontend Setup (React)**

**Folder Structure:**
```
frontend/
├── src/
│   ├── components/
│   │   └── UserTable.js
│   ├── App.js
│   └── index.js
└── public/
```

#### **2.1 Install Dependencies**
```bash
npx create-react-app frontend
cd frontend
npm install axios bootstrap
```

#### **2.2 `src/index.js`**
```javascript
import React from "react";
import ReactDOM from "react-dom";
import App from "./App";
import "bootstrap/dist/css/bootstrap.min.css";

ReactDOM.render(<App />, document.getElementById("root"));
```

#### **2.3 `src/App.js`**
```javascript
import React, { useEffect, useState } from "react";
import axios from "axios";
import UserTable from "./components/UserTable";

const App = () => {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    const res = await axios.get("http://localhost:5000/api/users");
    setUsers(res.data);
  };

  const handleDelete = async (id) => {
    await axios.delete(`http://localhost:5000/api/users/${id}`);
    fetchUsers();
  };

  return (
    <div className="container mt-5">
      <h2>User Management Dashboard</h2>
      <UserTable users={users} onDelete={handleDelete} />
    </div>
  );
};

export default App;
```

