app = Flask(__name__)

# Whitelist of allowed commands using absolute paths
ALLOWED_COMMANDS = {
    'ls': '/bin/ls',
    'pwd': '/bin/pwd',
    'whoami': '/usr/bin/whoami',
    'date': '/bin/date',
}

@app.route('/', methods=['GET'])
