@app.route('/execute', methods=['POST'])
def execute_command():
    command = request.form['command']
    try:
        # Split the command into parts safely
        args = shlex.split(command)
        if not args:
            return "No command provided", 400

        # Check if the command is allowed
        cmd = args[0]
        if cmd not in ALLOWED_COMMANDS.values() and cmd not in ALLOWED_COMMANDS.keys():
            return "Command not allowed", 400

        # Replace command name with absolute path from the whitelist
        if cmd in ALLOWED_COMMANDS.keys():
            args[0] = ALLOWED_COMMANDS[cmd]

        # Execute the command securely
        result = subprocess.run(args, capture_output=True, text=True, check=True, timeout=10)
        output = result.stdout
        error = result.stderr
    except subprocess.CalledProcessError as e:
        output = "Error: Command failed"
        error = str(e)
    except subprocess.TimeoutExpired:
        output = "Error: Command timed out"
        error = "Execution exceeded allowed time"
    except Exception as e:
        output = "Exception occurred"
        error = str(e)
    return render_template('result.html', output=output, error=error)

