Here's a basic authentication system implementation using Node.js, Express, and JSON Web Tokens (JWT). This example includes user registration, login, and protected routes.

**1. Install required dependencies:**
```bash
npm init -y
npm install express body-parser bcryptjs jsonwebtoken
```

**2. Basic Auth System Implementation (auth-app.js):**
```javascript
const express = require('express');
const bodyParser = require('body-parser');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const PORT = 3000;

const app = express();
app.use(bodyParser.json());

// In-memory "database"
const users = [];

// Secret key for JWT (store in environment variables in production)
const JWT_SECRET = 'your-secret-key-here';

// Register endpoint
app.post('/register', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Check if user exists
    if (users.some(user => user.username === username)) {
      return res.status(400).json({ message: 'User already exists' });
    }

    // Hash password
    const hashedPassword = await bcrypt.hash(password, 10);

    // Store user (in reality, you'd store in a database)
    users.push({ username, password: hashedPassword });

    res.status(201).json({ message: 'User created successfully' });
  } catch (error) {
    res.status(500).json({ message: 'Error creating user' });
  }
});

// Login endpoint
app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  // Find user
  const user = users.find(user => user.username === username);
  if (!user) {
    return res.status(401).json({ message: 'Authentication failed' });
  }

  // Check password
  const isValidPassword = await bcrypt.compare(password, user.password);
  if (!isValidPassword) {
    return res.status(401).json({ message: 'Authentication failed' });
  }

  // Generate JWT
  const token = jwt.sign({ username }, JWT_SECRET, { expiresIn: '1h' });

  res.json({ token });
});

// Protected route
app.get('/protected', authenticateToken, (req, res) => {
  res.json({ message: 'This is a protected route', user: req.user });
});

// Middleware to authenticate JWT
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Missing token' });
  }

  jwt.verify(token, JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ message: 'Invalid token' });
    }
    req.user = user;
    next();
  });
}

// Start server
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

**3. Example Requests:**

*Register a new user:*
```bash
curl -X POST http://localhost:3000/register \
  -H "Content-Type: application/json" \
  -d '{"username":"testuser","password":"testpass"}'
```

*Login and get token:*
```bash
curl -X POST http://localhost:3000/login \
  -H "Content-Type: application/json" \
  -d '{"username":"testuser","password":"testpass"}'
```

*Access protected route with token:*
```bash
curl http://localhost:3000/protected \
  -H "Authorization: Bearer <your-jwt-token>"
```

**Important Security Notes:**
1. In production, store `JWT_SECRET` in environment variables
2. Use HTTPS for all communications
3. Store users in a proper database (e.g., PostgreSQL, MongoDB)
4. Add input validation and rate limiting
5. Implement proper error handling
6. Use refresh tokens for longer sessions
7. Add CORS configuration if used with frontend applications

